+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.Records.Drawings
+{
+    /// <summary>
+    /// Direct coverage for <see cref="ProjectSightDMSService.SaveQuickLoadPDFWithAnnotsAndRotations"/>
+    /// (test-coverage.md row #68). Drives the public quick-load save path through
+    /// <see cref="DMSSystem.UpdateDMSPdfFileAsync"/> and asserts the modified PDF lands
+    /// in <c>WebFileUploadDirectory</c> with annotation/rotation changes applied.
+    /// </summary>
+    [TestClass]
+    public class QuickLoadPDFTests : TestBase
+    {
+        private const TestFiles FILE_TO_UPLOAD = TestFiles.UPLOAD_PDF_A1REV1;
+
+        // Single rectangle add operation in xfdf format.
+        private const string ANNOTATION_CHANGES =
+            "<?xml version=\"1.0\" encoding=\"UTF-8\" ?>\n" +
+            "<xfdf xmlns=\"http://ns.adobe.com/xfdf/\" xml:space=\"preserve\">\n" +
+            "<fields />\n" +
+            "<add><square page=\"0\" rect=\"100,100,200,200\" color=\"#C81922\" flags=\"print\" " +
+            "name=\"e7d0e3ce-1234-4abc-9def-1234567890ab\" title=\"private_user\" subject=\"Rectangle\" " +
+            "date=\"D:20260101000000-08'00'\" interior-color=\"#C81922\" opacity=\"0.33\" " +
+            "creationdate=\"D:20260101000000-08'00'\"/></add>\n" +
+            "<modify />\n" +
+            "<delete />\n" +
+            "</xfdf>";
+
+        [TestMethod]
+        public async Task QuickLoadPDFWithAnnotationChangesUpdatesFileInWebFileUploadDirectory()
+        {
+            var fileLink = await QuickUploadFirstLinkAsync(FILE_TO_UPLOAD);
+            fileLink.Should().NotBeNull("quick upload should produce a file link");
+            fileLink.FileVersionGUID.Should().NotBeEmpty("quick upload returns the staged file GUID");
+
+            var requestedBy = GenerateRequestedByProject();
+            string webFileUploadDirectory;
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                webFileUploadDirectory = portfolioDB.WebFileUploadDirectory;
+            }
+
+            var stagedPath = Path.Combine(webFileUploadDirectory, Global.CreateFileGUIDFromGUID(fileLink.FileVersionGUID));
+            File.Exists(stagedPath).Should().BeTrue("quick upload stages file in WebFileUploadDirectory");
+            var sizeBefore = new FileInfo(stagedPath).Length;
+            sizeBefore.Should().BeGreaterThan(0, "staged PDF should have content");
+
+            var request = new DMSPdfFileUpdateRequest
+            {
+                CurrentFileVersionId = 0,
+                UploadedFileGuid = fileLink.FileVersionGUID.ToString(),
+                AnnotationChanges = ANNOTATION_CHANGES,
+                PageRotations = new Dictionary<int, int> { { 1, 1 } }
+            };
+
+            var result = await new DMSSystem().UpdateDMSPdfFileAsync(request, requestedBy);
+
+            result.Should().NotBeNull();
+            using (new AssertionScope())
+            {
+                result.UploadedFileGuid.Should().Be(fileLink.FileVersionGUID.ToString(), "guid is preserved");
+                result.CurrentFileVersionId.Should().Be(0, "no DMS version is created on quick upload");
+                result.AnnotationsUpdated.Should().BeTrue("quick load reports the path was exercised");
+                result.Error.Should().BeNullOrEmpty("no error expected");
+            }
+
+            File.Exists(stagedPath).Should().BeTrue("modified PDF must remain in WebFileUploadDirectory");
+
+            var sizeAfter = new FileInfo(stagedPath).Length;
+            sizeAfter.Should().NotBe(sizeBefore, "rotation + annotation save should change PDF size");
+        }
+
+        [TestMethod]
+        public async Task QuickLoadPDFWithMissingTempFileReturnsWithoutError()
+        {
+            var requestedBy = GenerateRequestedByProject();
+            string webFileUploadDirectory;
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                webFileUploadDirectory = portfolioDB.WebFileUploadDirectory;
+            }
+
+            var orphanGuid = Guid.NewGuid();
+            var orphanPath = Path.Combine(webFileUploadDirectory, Global.CreateFileGUIDFromGUID(orphanGuid));
+            File.Exists(orphanPath).Should().BeFalse("test relies on a guid that has no staged file");
+
+            var request = new DMSPdfFileUpdateRequest
+            {
+                CurrentFileVersionId = 0,
+                UploadedFileGuid = orphanGuid.ToString(),
+                AnnotationChanges = ANNOTATION_CHANGES,
+                PageRotations = new Dictionary<int, int>()
+            };
+
+            var result = await new DMSSystem().UpdateDMSPdfFileAsync(request, requestedBy);
+
+            result.Should().NotBeNull();
+            using (new AssertionScope())
+            {
+                result.Error.Should().BeNullOrEmpty("missing temp file should be handled silently");
+                File.Exists(orphanPath).Should().BeFalse("no file should be created when temp is missing");
+            }
+        }
+    }
+}

