+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+using ProjectSight.DataAccess.DrawingsAndSpecifications;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.PDF
+{
+    /// <summary>
+    /// Direct coverage for <see cref="PDFTextHandler.ExtractPDFTextSegmentsToDB"/>
+    /// (test-coverage.md row #46). The method had no dedicated test on this branch.
+    /// Stages a published drawing PDF in <c>FMSDirectory</c>, then drives the text
+    /// extractor explicitly and asserts a <c>DrawingText</c> row is written.
+    /// </summary>
+    [TestClass]
+    public class PDFTextHandlerTests : TestBase
+    {
+        private const TestFiles DRAWING_TO_UPLOAD = TestFiles.UPLOAD_PDF_A1REV1;
+
+        private DrawingSet _drawingSet;
+
+        public override async Task CustomTestInitializeAsync()
+        {
+            await base.CustomTestInitializeAsync();
+
+            _drawingSet = await CreateDrawingSetAndUploadDrawingFilesAsync(DRAWING_TO_UPLOAD);
+            _drawingSet = await PublishDrawingsAsync(_drawingSet);
+        }
+
+        public override async Task CustomTestCleanupAsync()
+        {
+            if (_drawingSet != null)
+            {
+                await DeleteRecordAsync(_drawingSet);
+            }
+
+            ExecuteSQL($"DELETE FROM DrawingText WHERE ProjectID = {ContextProjectID}", ContextPortfolioId);
+
+            await base.CustomTestCleanupAsync();
+        }
+
+        [TestMethod]
+        public void ExtractPDFTextSegmentsToDBWritesSearchableTextRowForPublishedDrawing()
+        {
+            var drawing = _drawingSet.Drawings[0];
+            drawing.FileID.Should().BeGreaterThan(0, "published drawing should have FileID");
+
+            ExecuteSQL($"DELETE FROM DrawingText WHERE DrawingID = {drawing.DrawingID}", ContextPortfolioId);
+            QueryDrawingTextRowCount(drawing.DrawingID).Should().Be(0, "test starts with no text rows");
+
+            var request = new TextExtractRequest
+            {
+                TableType = PrologTable.Types.Drawing,
+                RecordID = drawing.DrawingID,
+                FileID = drawing.FileID,
+                AnnotationText = "extra-direct-call",
+                DeleteStoredProcedure = "s_enc_delete_DrawingText"
+            };
+
+            var error = new ErrorEncountered();
+            var requestedBy = GenerateRequestedByProject();
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                PDFTextHandler.ExtractPDFTextSegmentsToDB(portfolioDB, request, error, Logger);
+            }
+
+            error.HasError.Should().BeFalse(error.Message);
+            QueryDrawingTextRowCount(drawing.DrawingID).Should().Be(1, "direct call should write the searchable text row");
+
+            var searchableText = QueryDrawingSearchableText(drawing.DrawingID);
+            using (new AssertionScope())
+            {
+                searchableText.Should().NotBeNullOrEmpty("PDFTron should pull text from the FMS PDF");
+                searchableText.Should().Contain("extra-direct-call", "annotation text should be appended into the searchable text");
+            }
+        }
+
+        [TestMethod]
+        public void ExtractPDFTextSegmentsToDBWithUnknownFileIDReturnsWithoutError()
+        {
+            var drawing = _drawingSet.Drawings[0];
+
+            const int UNKNOWN_FILE_ID = -987654;
+            var request = new TextExtractRequest
+            {
+                TableType = PrologTable.Types.Drawing,
+                RecordID = drawing.DrawingID,
+                FileID = UNKNOWN_FILE_ID,
+                DeleteStoredProcedure = "s_enc_delete_DrawingText"
+            };
+
+            var error = new ErrorEncountered();
+            var requestedBy = GenerateRequestedByProject();
+
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                PDFTextHandler.ExtractPDFTextSegmentsToDB(portfolioDB, request, error, Logger);
+            }
+
+            error.HasError.Should().BeFalse("missing DMS file is logged as a warning, not raised as error");
+        }
+
+        #region Helpers
+
+        private int QueryDrawingTextRowCount(int drawingId)
+        {
+            var ds = ExecuteSQL($"SELECT COUNT(*) AS Cnt FROM DrawingText WHERE DrawingID = {drawingId}", ContextPortfolioId);
+            return Global.IntFromDB(ds.Tables[0].Rows[0]["Cnt"]);
+        }
+
+        private string QueryDrawingSearchableText(int drawingId)
+        {
+            var ds = ExecuteSQL($"SELECT SearchableText FROM DrawingText WHERE DrawingID = {drawingId}", ContextPortfolioId);
+            if (ds.Tables[0].Rows.Count == 0)
+            {
+                return null;
+            }
+
+            return Global.StrFromDB(ds.Tables[0].Rows[0]["SearchableText"]);
+        }
+
+        #endregion // Helpers
+    }
+}
