+using GCCM.Common.SystemFramework;
+using pdftron;
+using ProjectSight.Common.Components;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+
+namespace ProjectSight.Tests.IntegrationTests.Records.Drawings
+{
+    /// <summary>
+    /// Direct coverage for <see cref="DrawingRevisionRotationHandler.ConvertCoordinatesFromRotatedMatrixToNormal"/>
+    /// (test-coverage.md row #40) and <see cref="DrawingRevisionRotationHandler.ConvertCoordinatesFromNormalMatrixToRotated"/>
+    /// (row #41). The existing <c>UnitTests/DrawingTests/DrawingPageRotationTest</c> is
+    /// <c>[Ignore]</c> and inlines PDFTron operations rather than exercising the handler,
+    /// so this writes a narrow new test that stages a rotated drawing PDF in FMSDirectory
+    /// and invokes the internal handler directly. <see cref="InternalsVisibleToAttribute"/>
+    /// for <c>ProjectSight.Tests.ParallelIntegrationTests</c> is set on
+    /// <c>ProjectSight.BusinessLayer.DataAccess</c> via
+    /// <c>Drawings/PDFTronDocument.cs</c>.
+    /// </summary>
+    [TestClass]
+    public class DrawingRevisionRotationHandlerTests : TestBase
+    {
+        private const TestFiles ROTATED_REVISION = TestFiles.REVISION1_90_DEGREE;
+
+        // Square rectangle in raw PDF user-space coordinates. Picked deliberately not at
+        // the page origin so the matrix multiplication produces visibly different output.
+        private const double X1 = 100;
+        private const double Y1 = 200;
+        private const double X2 = 300;
+        private const double Y2 = 400;
+
+        private static readonly string s_squareXml =
+            $"<square page=\"0\" rect=\"{X1},{Y1},{X2},{Y2}\" color=\"#C81922\" flags=\"print\" " +
+            "name=\"d45e7a42-fb72-33be-02fb-a26b8cacb562\" title=\"private_user\" subject=\"Rectangle\" " +
+            "date=\"D:20200731131323-07'00'\" interior-color=\"#C81922\" creationdate=\"D:20200731131323-07'00'\" " +
+            "custom=\"{}\" xmlns=\"http://ns.adobe.com/xfdf/\" />";
+
+        private Guid _stagedFileGuid;
+        private string _stagedFmsPath;
+
+        public override async Task CustomTestInitializeAsync()
+        {
+            await base.CustomTestInitializeAsync();
+
+            PDFNet.Initialize(Support.PDFTRON_PDFNETSDK_KEY);
+
+            _stagedFileGuid = Guid.NewGuid();
+
+            var requestedBy = GenerateRequestedByProject();
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                var fmsDirectory = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+                _stagedFmsPath = Path.Combine(fmsDirectory, Global.CreateFileGUIDFromGUID(_stagedFileGuid));
+            }
+
+            File.Copy(GetFilePath(ROTATED_REVISION), _stagedFmsPath, overwrite: true);
+        }
+
+        public override async Task CustomTestCleanupAsync()
+        {
+            if (!string.IsNullOrEmpty(_stagedFmsPath))
+            {
+                Global.KillAFile(_stagedFmsPath, true);
+            }
+
+            await base.CustomTestCleanupAsync();
+        }
+
+        [TestMethod]
+        public void ConvertCoordinatesFromRotatedMatrixToNormalTransformsSquareRectViaPageDefaultMatrix()
+        {
+            var oldAnnotation = NewSquareAnnotation();
+            var newAnnotation = NewSquareAnnotation();
+
+            var requestedBy = GenerateRequestedByProject();
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                DrawingRevisionRotationHandler.ConvertCoordinatesFromRotatedMatrixToNormal(
+                    portfolioDB,
+                    oldAnnotation,
+                    newAnnotation,
+                    _stagedFileGuid,
+                    oldRotation: 90,
+                    newRotation: 0,
+                    Logger);
+            }
+
+            newAnnotation.XmlData.Should().NotBeNull();
+            using (new AssertionScope())
+            {
+                newAnnotation.XmlData.Should().NotBe(oldAnnotation.XmlData,
+                    "rect should be transformed when rotation differs");
+
+                var rect = ParseRect(newAnnotation.XmlData);
+                rect.Should().NotBeNull("transformed XML must contain a rect attribute");
+                (rect[0] != X1 || rect[1] != Y1 || rect[2] != X2 || rect[3] != Y2).Should().BeTrue(
+                    "transformed coordinates should differ from the originals");
+            }
+        }
+
+        [TestMethod]
+        public void ConvertCoordinatesFromNormalMatrixToRotatedTransformsSquareRectViaInverseMatrix()
+        {
+            var oldAnnotation = NewSquareAnnotation();
+            var newAnnotation = NewSquareAnnotation();
+
+            var requestedBy = GenerateRequestedByProject();
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                DrawingRevisionRotationHandler.ConvertCoordinatesFromNormalMatrixToRotated(
+                    portfolioDB,
+                    oldAnnotation,
+                    newAnnotation,
+                    _stagedFileGuid,
+                    oldRotation: 0,
+                    newRotation: 90,
+                    Logger);
+            }
+
+            newAnnotation.XmlData.Should().NotBeNull();
+            using (new AssertionScope())
+            {
+                newAnnotation.XmlData.Should().NotBe(oldAnnotation.XmlData,
+                    "inverse-matrix transform should change rect");
+
+                var rect = ParseRect(newAnnotation.XmlData);
+                rect.Should().NotBeNull("transformed XML must contain a rect attribute");
+                (rect[0] != X1 || rect[1] != Y1 || rect[2] != X2 || rect[3] != Y2).Should().BeTrue(
+                    "transformed coordinates should differ from the originals");
+            }
+        }
+
+        [TestMethod]
+        public void ConvertCoordinatesRoundTripBetweenMatricesReturnsApproximatelyOriginalCoordinates()
+        {
+            var oldAnnotation = NewSquareAnnotation();
+            var normalized = NewSquareAnnotation();
+            var rotatedBack = NewSquareAnnotation();
+
+            var requestedBy = GenerateRequestedByProject();
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(requestedBy, requestedBy.ProjectID))
+            {
+                DrawingRevisionRotationHandler.ConvertCoordinatesFromRotatedMatrixToNormal(
+                    portfolioDB, oldAnnotation, normalized, _stagedFileGuid,
+                    oldRotation: 90, newRotation: 0, Logger);
+
+                DrawingRevisionRotationHandler.ConvertCoordinatesFromNormalMatrixToRotated(
+                    portfolioDB, normalized, rotatedBack, _stagedFileGuid,
+                    oldRotation: 0, newRotation: 90, Logger);
+            }
+
+            var roundTripped = ParseRect(rotatedBack.XmlData);
+            roundTripped.Should().NotBeNull();
+
+            var minX = Math.Min(X1, X2);
+            var minY = Math.Min(Y1, Y2);
+            var maxX = Math.Max(X1, X2);
+            var maxY = Math.Max(Y1, Y2);
+
+            using (new AssertionScope())
+            {
+                roundTripped[0].Should().BeApproximately(minX, 0.01, "round-trip x1");
+                roundTripped[1].Should().BeApproximately(minY, 0.01, "round-trip y1");
+                roundTripped[2].Should().BeApproximately(maxX, 0.01, "round-trip x2");
+                roundTripped[3].Should().BeApproximately(maxY, 0.01, "round-trip y2");
+            }
+        }
+
+        #region Helpers
+
+        private Annotation NewSquareAnnotation()
+        {
+            return new Annotation
+            {
+                GUID = Guid.NewGuid(),
+                UserID = m_oCaller.ID,
+                ProjectID = m_oProject.ProjectID,
+                CreatedBy = m_oCaller.Login,
+                WhenCreated = DateTime.Now,
+                LastModified = DateTime.Now,
+                LastModifiedBy = m_oCaller.Login,
+                IsImported = false,
+                IsResolved = true,
+                XmlData = s_squareXml
+            };
+        }
+
+        private static double[] ParseRect(string xmlData)
+        {
+            xmlData.Should().NotBeNullOrEmpty();
+
+            const string rectAttr = "rect=\"";
+            var idx = xmlData.IndexOf(rectAttr, StringComparison.Ordinal);
+            if (idx < 0)
+            {
+                return null;
+            }
+
+            var start = idx + rectAttr.Length;
+            var end = xmlData.IndexOf('"', start);
+            if (end < 0)
+            {
+                return null;
+            }
+
+            var raw = xmlData.Substring(start, end - start).Split(',');
+            if (raw.Length != 4)
+            {
+                return null;
+            }
+
+            return new[]
+            {
+                double.Parse(raw[0].Trim(), System.Globalization.CultureInfo.InvariantCulture),
+                double.Parse(raw[1].Trim(), System.Globalization.CultureInfo.InvariantCulture),
+                double.Parse(raw[2].Trim(), System.Globalization.CultureInfo.InvariantCulture),
+                double.Parse(raw[3].Trim(), System.Globalization.CultureInfo.InvariantCulture)
+            };
+        }
+
+        #endregion // Helpers
+    }
+}
