+using GCCM.Common.SystemFramework;
+using ProjectSight.Common.Components;
+using ProjectSight.DataAccess.SiteCapture.Processing.CaptureProcessor;
+
+namespace ProjectSight.Tests.IntegrationTests.SiteCapture.Processing.Captures
+{
+    [TestClass]
+    public class ProcessCaptureSystemPositionTests : SiteCaptureTestBase
+    {
+        private ProcessCaptureSystem _captureUploadSystem;
+
+        public override async Task CustomTestInitializeAsync()
+        {
+            await base.CustomTestInitializeAsync();
+            _captureUploadSystem = new ProcessCaptureSystem(m_siteCaptureAPIServiceMock, m_externalFileServiceMock);
+        }
+
+        [TestMethod]
+        public async Task ProcessRequestAsync_MarksRequestFailed_WhenDrawingPdfMissingFromFMS()
+        {
+            var uploadRequest = await CreateAndSubmitSiteCaptureCompletionRequestAsync(completeProcessing: true);
+            var deletedPdfPath = DeletePublishedDrawingPdfFromFMS(uploadRequest.DrawingId);
+            try
+            {
+                await _captureUploadSystem.ProcessRequestAsync(uploadRequest, default);
+                var updated = GetSiteCaptureUploadRequest(uploadRequest.RecordId);
+                updated.Status.Should().Be(SiteCaptureUploadRequest.Statuses.Failed);
+                updated.FailureReason.Should().Contain("Drawing PDF file was not found");
+            }
+            finally
+            {
+                if (File.Exists(deletedPdfPath)) { try { File.Delete(deletedPdfPath); } catch { } }
+            }
+        }
+
+        private string DeletePublishedDrawingPdfFromFMS(int drawingId)
+        {
+            using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), ContextProjectID);
+            var fmsDirectory = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+            var raw = Global.StrFromDB(portfolioDB.ExecuteScalar($"SELECT TOP 1 FileVersionGUID FROM Drawings WHERE DrawingID = {drawingId}"));
+            Guid.TryParse(raw, out var guid).Should().BeTrue();
+            var pdfPath = Path.Combine(fmsDirectory, Global.CreateFileGUIDFromGUID(guid));
+            File.Delete(pdfPath);
+            return pdfPath;
+        }
+    }
+}
