+using ProjectSight.Common.Components;
+using ProjectSight.DataAccess.SiteCapture;
+
+namespace ProjectSight.Tests.IntegrationTests.SiteCapture
+{
+    [TestClass]
+    public class SiteCaptureStationLinksTests : TestBase
+    {
+        private static readonly byte[] _samplePayload = { 0xFF, 0xD8, 0xFF, 0xE0, 0x10, 0x20, 0x30, 0x40 };
+        private string _stagedFolder;
+
+        public override async Task CustomTestCleanupAsync()
+        {
+            if (!string.IsNullOrEmpty(_stagedFolder) && Directory.Exists(_stagedFolder))
+            {
+                try { Directory.Delete(_stagedFolder, recursive: true); } catch { }
+            }
+            await base.CustomTestCleanupAsync();
+        }
+
+        [TestMethod]
