+using ProjectSight.Common.Components;
+using ProjectSight.Common.Components.SiteCapture.API.Enums;
+using ProjectSight.DataAccess.SiteCapture;
+using static ProjectSight.Tests.Builders.TestDataBuilder;
+using BinaryData = ProjectSight.Common.Components.BinaryData;
+
+namespace ProjectSight.Tests.IntegrationTests.SiteCapture.SiteCaptureViewer
+{
+    [TestClass]
+    public class SiteCaptureViewerImageTests : TestBase
+    {
+        private const TestFiles DRAWING_TO_UPLOAD = TestFiles.UPLOAD_PDF_A2_000A;
+        private static readonly byte[] _jpegPayload = { 0xFF, 0xD8, 0xFF, 0xE0, 0x10, 0x11, 0x12, 0x13 };
+        private readonly List<string> _stagedFolders = new();
+
+        public override async Task CustomTestCleanupAsync()
+        {
+            foreach (var folder in _stagedFolders)
+            {
+                if (Directory.Exists(folder)) { try { Directory.Delete(folder, recursive: true); } catch { } }
+            }
+            await base.CustomTestCleanupAsync();
+        }
+
+        [TestMethod]
+        public async Task GetSiteCaptureStationThumbnail_PopulatesBinaryDataWithStagedBytes()
+        {
+            var (station, mayaFloorId) = await CreateStationWithMayaFloorIdAsync();
+            StageStationImage(mayaFloorId, station.MayaStationId, _jpegPayload);
+            var binaryData = new BinaryData { Key = station.SiteCaptureStationId.ToString(), Source = BinaryData.Sources.SiteCaptureStationThumbnail };
+            new SiteCaptureViewerSystem(_dbHelperFactory).GetSiteCaptureStationThumbnail(GenerateRequestedByProject(), binaryData);
+            binaryData.Data.Should().BeEquivalentTo(_jpegPayload);
+        }
+
+        [TestMethod]
+        public void GetSiteCaptureFloorImage_PopulatesBinaryDataWithStagedBytes()
+        {
+            var mayaFloorId = Guid.NewGuid().ToString();
+            StageFloorImage(mayaFloorId, new byte[] { 0x89, 0x50, 0x4E, 0x47 });
+            var binaryData = new BinaryData { Key = mayaFloorId, Source = BinaryData.Sources.SiteCaptureFloorImage };
+            new SiteCaptureViewerSystem(_dbHelperFactory).GetSiteCaptureFloorImage(GenerateRequestedByProject(), binaryData);
+            binaryData.Mime.Should().Be("image/png");
+        }
+
+        private async Task<(SiteCaptureStation station, string mayaFloorId)> CreateStationWithMayaFloorIdAsync()
+        {
+            var drawing = await CreateDrawingWithSiteCaptureAnnotations(m_oCaller, DRAWING_TO_UPLOAD, SITE_CAPTURE_VIDEO);
+            var mayaFloorId = Guid.NewGuid().ToString();
+            using (var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject()))
+            {
+                portfolioDB.ExecuteNonQuery($"UPDATE DrawingSeries SET MayaFloorId = '{mayaFloorId}' WHERE DrawingSeriesID = {drawing.DrawingSeriesID}");
+            }
+            var capture = await AddSiteCaptureRecordToAnnotation(drawing.Annotations.First(), Generate.String("Cap"), DateTimeOffset.UtcNow, CaptureTypes.Video);
+            return (await AddSiteCaptureStationToSiteCapture(capture.SiteCaptureId), mayaFloorId);
+        }
+
+        private void StageStationImage(string mayaFloorId, string mayaStationId, byte[] payload)
+        {
+            using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), ContextProjectID);
+            var folder = SiteCaptureImageSupport.GetPathToFloorFolder(portfolioDB, mayaFloorId);
+            Directory.CreateDirectory(folder);
+            _stagedFolders.Add(folder);
+            File.WriteAllBytes(SiteCaptureImageSupport.GetFullPathToStationImage(portfolioDB, mayaFloorId, mayaStationId, SiteCaptureImageSupport.StationImageTypes.HighThumb), payload);
+        }
+
+        private void StageFloorImage(string mayaFloorId, byte[] payload)
+        {
+            using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), ContextProjectID);
+            var folder = SiteCaptureImageSupport.GetPathToFloorFolder(portfolioDB, mayaFloorId);
+            Directory.CreateDirectory(folder);
+            _stagedFolders.Add(folder);
+            File.WriteAllBytes(SiteCaptureImageSupport.GetFullPathToFloorImage(portfolioDB, mayaFloorId, SiteCaptureImageSupport.FloorImageTypes.High), payload);
+        }
+    }
+}
