+        {
+            using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), m_oProject.ProjectID);
+            var fmsDirectory = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+            var serverFilePath = Path.Combine(fmsDirectory, Global.CreateFileGUIDFromGUID(Guid.NewGuid()));
+            File.WriteAllBytes(serverFilePath, new byte[] { 1, 1, 1 });
+            var newBytes = new byte[] { 2, 2, 2, 2 };
+            var client = SubstituteForClientWithDownload(newBytes);
+
+            try
+            {
+                await InvokeDownloadFileAsync(new TCMigrationReversalSystem(), client, "tc-file-id", serverFilePath, CancellationToken.None);
+                File.ReadAllBytes(serverFilePath).Should().Equal(newBytes);
+            }
+            finally
+            {
+                Global.KillAFile(serverFilePath, true);
+            }
+        }
+
+        [TestMethod]
+        public async Task DownloadAndUpdateDMSFileAsyncWritesFileToFMSDirectory()
+        {
+            using var ignitionDB = _dbHelperFactory.NewDBHelperIgnition();
+            using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), m_oProject.ProjectID);
+            var fileGuid = Guid.NewGuid();
+            var expectedPath = Path.Combine(ProjectSightDMSService.GetFMSDirectory(portfolioDB), Global.CreateFileGUIDFromGUID(fileGuid));
+            var fileBytes = new byte[] { 5, 5, 5 };
+            var client = SubstituteForClientWithDownload(fileBytes);
+            var folderItem = new FolderItem { Identifier = "tc-id", Name = "test.bin", CreatedOn = DateTimeOffset.UtcNow, CreatedBy = new Person { Email = "t@e.com" } };
+
+            try
+            {
+                using var context = new TCMigrationReversalSystem.MigrateFolderContext(portfolioDB, ignitionDB, client, CancellationToken.None);
+                try { await InvokeDownloadAndUpdateDMSFileAsync(new TCMigrationReversalSystem(), folderItem, fileGuid, 0, context); } catch { }
+                File.ReadAllBytes(expectedPath).Should().Equal(fileBytes);
+            }
+            finally
+            {
+                Global.KillAFile(expectedPath, true);
+            }
+        }
+
+        [TestMethod]
+        public async Task FetchNonPersistedQueuedFilePropertiesReturnsZeroWhenPortfolioOffline()
+        {
+            var request = new TCMigrationReversalQueuedFile { OrganizationID = m_oPortfolioId, ProjectID = m_oProject.ProjectID, FileGUID = Guid.NewGuid() };
+            int result = 0;
+            await ExecuteTestWithPortfolioOfflineAsync(() => { result = InvokeFetch(request); return Task.CompletedTask; });
+            result.Should().Be(0);
+            request.ServerFilePath.Should().BeNullOrEmpty();
+        }
+
+        [TestMethod]
+        public void FetchNonPersistedQueuedFilePropertiesResolvesFMSFilePath()
+        {
+            using var portfolioDB = _dbHelperFactory.NewDBHelperPortfolio(GenerateRequestedByProject(), m_oProject.ProjectID);
+            var fmsDirectory = ProjectSightDMSService.GetFMSDirectory(portfolioDB);
+            var request = new TCMigrationReversalQueuedFile { OrganizationID = m_oPortfolioId, ProjectID = m_oProject.ProjectID, FileGUID = Guid.NewGuid() };
+            InvokeFetch(request).Should().BeGreaterThan(0);
