+            request.ServerFilePath.Should().EndWith(Global.CreateFileGUIDFromGUID(request.FileGUID));
+        }
+
+        private static IProjectClient SubstituteForClientWithDownload(byte[] payload)
+        {
+            var client = Substitute.For<IProjectClient>();
+            var files = Substitute.For<IFiles>();
+            client.Files.Returns(files);
+            files.DownloadAsync(Arg.Any<string>(), cancellationToken: Arg.Any<CancellationToken>())
+                .Returns(_ => Task.FromResult<Stream>(new MemoryStream(payload)));
+            return client;
+        }
+
+        private static async Task InvokeDownloadFileAsync(TCMigrationReversalSystem system, IProjectClient client, string tcFileId, string serverFilePath, CancellationToken cancellationToken)
+        {
+            var method = typeof(TCMigrationReversalSystem).GetMethod("DownloadFileAsync", BindingFlags.Instance | BindingFlags.NonPublic, null, new[] { typeof(IProjectClient), typeof(string), typeof(string), typeof(CancellationToken) }, null);
+            await ((Task)method.Invoke(system, new object[] { client, tcFileId, serverFilePath, cancellationToken })).ConfigureAwait(false);
+        }
+
+        private static async Task InvokeDownloadAndUpdateDMSFileAsync(TCMigrationReversalSystem system, FolderItem folderItem, Guid fileGuid, int parentFolderId, TCMigrationReversalSystem.MigrateFolderContext context)
+        {
+            var method = typeof(TCMigrationReversalSystem).GetMethod("DownloadAndUpdateDMSFileAsync", BindingFlags.Instance | BindingFlags.NonPublic, null, new[] { typeof(FolderItem), typeof(Guid), typeof(int), typeof(TCMigrationReversalSystem.MigrateFolderContext) }, null);
+            await ((Task)method.Invoke(system, new object[] { folderItem, fileGuid, parentFolderId, context })).ConfigureAwait(false);
+        }
+
+        private static int InvokeFetch(TCMigrationReversalQueuedFile request) =>
+            (int)typeof(TCMigrationReversalSystem).GetMethod("FetchNonPersistedQueuedFileProperties", BindingFlags.Instance | BindingFlags.NonPublic)
+                .Invoke(new TCMigrationReversalSystem(), new object[] { request });
+    }
+}
